def count_nonzero_weights(self):
counter = 0
for params in list(self.parameters()):
counter += torch.count_nonzero(params).item()
return counter
def count_total_weights(self):
counter = 0
for params in list(self.parameters()):
counter += torch.numel(params)
return counter
```

